### CheckersBoard Class
This class will represent the 8x8 checkers board and provide methods to update and display the board state.

```python
class CheckersBoard:
    def __init__(self):
        self.board = [[' ' for _ in range(8)] for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize pieces on the board
        piece_types = ['b', 'r']  # 'b' for black, 'r' for red
        for i in range(3):
            for j in range(0, 8, 2):
                self.board[i][j] = piece_types[(i + j) % 2]
        for i in range(5, 8):
            for j in range(1, 9, 2):
                self.board[i][j] = piece_types[(i + j) % 2]

    def display_board(self):
        for row in self.board:
            print(' '.join(row))

    def move_piece(self, start_pos, end_pos):
        # Move a piece from start position to end position
        start_row, start_col = start_pos[0], start_pos[1]
        end_row, end_col = end_pos[0], end_pos[1]
        if self.board[start_row][start_col] != ' ':
            self.board[end_row][end_col] = self.board[start_row][start_col]
            self.board[start_row][start_col] = ' '
            return True
        return False

    def is_valid_move(self, start_pos, end_pos):
        # Check if the move is valid
        start_row, start_col = start_pos[0], start_pos[1]
        end_row, end_col = end_pos[0], end_pos[1]
        piece = self.board[start_row][start_col]

        if (end_row < 0 or end_row > 7 or end_col < 0 or end_col > 7):
            return False

        # Basic movement
        if piece.islower():
            valid_move = abs(end_row - start_row) == 1 and abs(end_col - start_col) == 1
        else:
            valid_move = abs(end_row - start_row) in [1, 2] and abs(end_col - start_col) == 1

        # Check if the move ends on an opponent's piece or a valid square
        end_square = self.board[end_row][end_col]
        if (end_square != ' ' and end_square.isupper()) or (valid_move and end_square == ' '):
            return True

        return False

    def capture_piece(self, start_pos, end_pos):
        # Capture an opponent's piece
        start_row, start_col = start_pos[0], start_pos[1]
        end_row, end_col = end_pos[0], end_pos[1]
        captured_row, captured_col = (start_row + end_row) // 2, (start_col + end_col) // 2
        if self.board[start_row][start_col].islower() and self.board[end_row][end_col].isupper():
            self.board[captured_row][captured_col] = ' '
        elif self.board[start_row][start_col].isupper() and self.board[end_row][end_col].islower():
            self.board[captured_row][captured_col] = ' '

    def is_game_over(self):
        # Check if the game is over
        pieces_left = sum(row.count('r') for row in self.board) + sum(row.count('R') for row in self.board)
        if pieces_left <= 12:
            return True
        return False

    def promote_piece(self, pos):
        # Promote a piece to a king
        row, col = pos[0], pos[1]
        if self.board[row][col].islower() and row == 7:
            self.board[row][col] = 'R'
        elif self.board[row][col].isupper() and row == 0:
            self.board[row][col] = 'r'
