class Player:
    def __init__(self, pieces_color):
        self.pieces_color = pieces_color

    def get_moves(self, board):
        # Get valid moves for the player's pieces
        moves = []
        for i in range(8):
            for j in range(8):
                piece = board[i][j]
                if piece != ' ' and piece.islower() == (self.pieces_color == 'r'):
                    moves.extend(self.get_moves_for_piece(board, (i, j)))
        return moves

    def get_moves_for_piece(self, board, pos):
        # Get valid moves for a specific piece
        row, col = pos[0], pos[1]
        moves = []
        if row >= 0 and row < 8 and col >= 0 and col < 8:
            current_piece = board[row][col]
            if (current_piece.islower() and self.pieces_color == 'r') or (current_piece.isupper() and self.pieces_color == 'b'):
                moves.extend(self.get_basic_moves(board, pos))
                moves.extend(self.get_capture_moves(board, pos))
        return moves

    def get_basic_moves(self, board, pos):
        # Get basic one-step moves for a piece
        row, col = pos[0], pos[1]
        moves = []
        if row + 1 < 8 and (col + 1 < 8 or col - 1 >= 0):
            if row + 1 < 8 and col + 1 < 8:
                moves.append(((row, col), (row + 1, col + 1)))
            if row + 1 < 8 and col - 1 >= 0:
                moves.append(((row, col), (row + 1, col - 1)))
        return moves

    def get_capture_moves(self, board, pos):
        # Get capture moves for a piece
        row, col = pos[0], pos[1]
        captures = []
        if row + 2 < 8 and (col + 2 < 8 or col - 2 >= 0):
            if row + 2 < 8 and col + 2 < 8:
                jumps = board[row + 1][col + 1]
                if jumps.isupper() and self.pieces_color == 'r':
                    captures.append(((row, col), (row + 2, col + 2)))
