                jumps = board[row + 1][col - 1]
                if jumps.isupper() and self.pieces_color == 'r':
                    captures.append(((row, col), (row + 2, col - 2)))
        return captures

    def make_move(self, start_pos, end_pos, board):
        # Make a move on the board
        board.move_piece(start_pos, end_pos)
        if abs(end_pos[0] - start_pos[0]) == 2:
            board.capture_piece(start_pos, end_pos)
        if self.pieces_color == 'r' and end_pos[0] == 7 or self.pieces_color == 'b' and end_pos[0] == 0:
            board.promote_piece(end_pos)

