### GameLogic Class
This class will handle the game logic, such as move validation and capturing.

```python
class GameLogic:
    def __init__(self, player1, player2):
        self.player1 = player1
        self.player2 = player2
        self.current_player = self.player1
        self.board = CheckersBoard()

    def switch_players(self):
        # Switch between players
        if self.current_player == self.player1:
            self.current_player = self.player2
        else:
            self.current_player = self.player1

    def make_move(self, start_pos, end_pos):
        # Make a move on the board
        if self.board.is_valid_move(start_pos, end_pos):
            self.current_player.make_move(start_pos, end_pos, self.board)
            return True
        return False

    def check_game_over(self):
        # Check if the game is over
        if self.board.is_game_over():
            return True
        return False

    def play(self):
        # Play the game
        while not self.check_game_over():
            self.board.display_board()
            moves = self.current_player.get_moves(self.board)
            if len(moves) == 0:
                print(f"Player {self.current_player.pieces_color} has no valid moves. Game Over.")
                return
            print(f"Player {self.current_player.pieces_color}'s turn")
            start_pos, end_pos = input("Enter move (start_pos-end_pos): ").split('-')
            start_pos = tuple(map(int, start_pos.split(',')))
            end_pos = tuple(map(int, end_pos.split(',')))
            if self.make_move(start_pos, end_pos):
                self.switch_players()
        self.board.display_board()
        print(f"Player {self.current_player.pieces_color} wins!")
```

